mapper.select:
SELECT IFNULL(SUM(carbon_reduction), 0)
FROM behavior_record
WHERE user_id = #{userId}
  AND record_date BETWEEN #{startDate} AND #{endDate}

mapper.insert:
INSERT INTO behavior_record (
    user_id, behavior_type_id, value, carbon_reduction, record_date, create_time
) VALUES (
             #{userId}, #{behaviorTypeId}, #{value}, #{carbonReduction}, #{recordDate}, NOW()
         )
